solution_code:
#include <stdio.h>

void swap_int(int *a, int *b) {
    int tmp = *a;
    *a = *b;
    *b = tmp;
}

void set_via_ptr(int **pp, int val) {
    **pp = val;
}

validation.test_code:
void test_swap_basic(void) {
    int x = 3, y = 7;
    swap_int(&x, &y);
    TEST_ASSERT_EQUAL_INT(7, x);
    TEST_ASSERT_EQUAL_INT(3, y);
}

void test_swap_same_value(void) {
    int x = 5, y = 5;
    swap_int(&x, &y);
    TEST_ASSERT_EQUAL_INT(5, x);
    TEST_ASSERT_EQUAL_INT(5, y);
}

void test_swap_negative(void) {
    int x = -10, y = 42;
    swap_int(&x, &y);
    TEST_ASSERT_EQUAL_INT(42, x);
    TEST_ASSERT_EQUAL_INT(-10, y);
}

void test_set_via_ptr(void) {
    int target = 0;
    int *p = &target;
    set_via_ptr(&p, 99);
    TEST_ASSERT_EQUAL_INT(99, target);
}

void test_set_via_ptr_overwrite(void) {
    int val = 1000;
    int *p = &val;
    set_via_ptr(&p, -1);
    TEST_ASSERT_EQUAL_INT(-1, val);
}

int main(void) {
    RUN_TEST(test_swap_basic);
    RUN_TEST(test_swap_same_value);
    RUN_TEST(test_swap_negative);
    RUN_TEST(test_set_via_ptr);
    RUN_TEST(test_set_via_ptr_overwrite);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}
